  1: package com.example.calculator
  2: 
  3: import kotlin.math.floor
  4: import kotlin.math.pow
  5: import kotlin.math.sqrt
  6: 
  7: object CalculatorEngine {
  8: 
  9:     fun formatNumber(v: Double): String =
  10:         if (v == floor(v) && !v.isInfinite()) v.toLong().toString()
  11:         else "%.10g".format(v).trimEnd('0').trimEnd('.')
  12: 
  13:     fun safeEvaluate(expr: String, variables: Map<String, Double?>, shortcuts: Map<String, String> = emptyMap()): String {
  14:         if (expr.isEmpty()) return "0"
  15:         return try {
  16:             val cleanedExpr = preProcessVoiceQuery(expr)
  17:             val expandedExpr = expandShortcuts(cleanedExpr, shortcuts)
  18:             val value = evaluate(expandedExpr, variables)
  19:             if (value.isNaN() || value.isInfinite()) "Error" else formatNumber(value)
  20:         } catch (_: Exception) {
  21:             "Error"
  22:         }
  23:     }
  24: 
  25:     private fun preProcessVoiceQuery(query: String): String {
  26:         return query.lowercase()
  27:             .replace("square root", "√")
  28:             .replace("root", "√")
  29:             .replace("parentheses", "(")
  30:             .replace("open bracket", "(")
  31:             .replace("closed bracket", ")")
  32:             .replace("close bracket", ")")
  33:             .replace("to the power of", "^")
  34:             .replace("times", "×")
  35:             .replace("multiplied by", "×")
  36:             .replace("divided by", "÷")
  37:             .replace("plus", "+")
  38:             .replace("minus", "−")
  39:     }
  40: 
  41:     private fun expandShortcuts(expr: String, shortcuts: Map<String, String>): String {
  42:         var currentExpr = expr
  43:         // Expand shortcuts iteratively in case of nested shortcuts (max 10 depth to prevent recursion)
  44:         for (i in 0 until 10) {
  45:             var expanded = false
  46:             for ((name, value) in shortcuts) {
  47:                 val token = "\$$name"
  48:                 if (currentExpr.contains(token)) {
  49:                     currentExpr = currentExpr.replace(token, value)
  50:                     expanded = true
  51:                 }
  52:             }
  53:             if (!expanded) break
  54:         }
  55:         return currentExpr
  56:     }
  57: 
  58:     private fun evaluate(expr: String, variables: Map<String, Double?>): Double {
  59:         val tokens = tokenize(expr)
  60:         val pos = intArrayOf(0)
  61:         val result = parseAddSub(tokens, pos, variables)
  62:         if (pos[0] != tokens.size) throw IllegalArgumentException("Unexpected token")
  63:         return result
  64:     }
  65: 
  66:     private fun tokenize(expr: String): List<String> {
  67:         val normalized = expr
  68:             .replace('×', '*')
  69:             .replace('÷', '/')
  70:             .replace('−', '-')
  71:         val list = mutableListOf<String>()
  72:         var i = 0
  73:         while (i < normalized.length) {
  74:             val c = normalized[i]
  75:             when {
  76:                 c == '$' -> {
  77:                     val sb = StringBuilder()
  78:                     sb.append('$')
  79:                     i++
  80:                     while (i < normalized.length && (normalized[i].isLetter() || normalized[i].isDigit())) {
  81:                         sb.append(normalized[i++])
  82:                     }
  83:                     list += sb.toString()
  84:                 }
  85:                 c.isDigit() || c == '.' -> {
  86:                     val sb = StringBuilder()
  87:                     while (i < normalized.length && (normalized[i].isDigit() || normalized[i] == '.')) {
  88:                         sb.append(normalized[i++])
  89:                     }
  90:                     list += sb.toString()
  91:                 }
  92:                 normalized.startsWith("sqrt", i) -> {
  93:                     list += "√"
  94:                     i += 4
  95:                 }
  96:                 c in listOf('+', '-', '*', '/', '^', '(', ')', '%', '√') -> {
  97:                     list += c.toString()
  98:                     i++
  99:                 }
  100:                 c.isWhitespace() || c == '=' -> i++
  101:                 else -> i++
  102:             }
  103:         }
  104:         return list
  105:     }
  106: 
  107:     private fun parseAddSub(tokens: List<String>, pos: IntArray, variables: Map<String, Double?>): Double {
  108:         var value = parseMulDiv(tokens, pos, variables)
  109:         while (pos[0] < tokens.size && tokens[pos[0]] in listOf("+", "-")) {
  110:             val op = tokens[pos[0]++]
  111:             val right = parseMulDiv(tokens, pos, variables)
  112:             value = if (op == "+") value + right else value - right
  113:         }
  114:         return value
  115:     }
  116: 
  117:     private fun parseMulDiv(tokens: List<String>, pos: IntArray, variables: Map<String, Double?>): Double {
  118:         var value = parsePower(tokens, pos, variables)
  119:         while (pos[0] < tokens.size) {
  120:             when {
  121:                 tokens[pos[0]] in listOf("*", "/") -> {
  122:                     val op = tokens[pos[0]++]
  123:                     val right = parsePower(tokens, pos, variables)
  124:                     value = if (op == "*") value * right else value / right
  125:                 }
  126:                 tokens[pos[0]].startsImplicitMultiplication() -> {
  127:                     val right = parsePower(tokens, pos, variables)
  128:                     value *= right
  129:                 }
  130:                 else -> return value
  131:             }
  132:         }
  133:         return value
  134:     }
  135: 
  136:     private fun parsePower(tokens: List<String>, pos: IntArray, variables: Map<String, Double?>): Double {
  137:         var value = parseUnary(tokens, pos, variables)
  138:         if (pos[0] < tokens.size && tokens[pos[0]] == "^") {
  139:             pos[0]++
  140:             val exponent = parsePower(tokens, pos, variables)
  141:             value = value.pow(exponent)
  142:         }
  143:         return value
  144:     }
  145: 
  146:     private fun parseUnary(tokens: List<String>, pos: IntArray, variables: Map<String, Double?>): Double {
  147:         if (pos[0] >= tokens.size) throw IllegalArgumentException("Unexpected end")
  148:         return when (tokens[pos[0]]) {
  149:             "+" -> { pos[0]++; parseUnary(tokens, pos, variables) }
  150:             "-" -> { pos[0]++; -parseUnary(tokens, pos, variables) }
  151:             "√" -> { pos[0]++; sqrt(parseUnary(tokens, pos, variables)) }
  152:             else -> parsePrimary(tokens, pos, variables)
  153:         }
  154:     }
  155: 
  156:     private fun parsePrimary(tokens: List<String>, pos: IntArray, variables: Map<String, Double?>): Double {
  157:         if (pos[0] >= tokens.size) throw IllegalArgumentException("Unexpected end")
  158:         val token = tokens[pos[0]++]
  159:         return when {
  160:             token == "(" -> {
  161:                 val value = parseAddSub(tokens, pos, variables)
  162:                 if (pos[0] >= tokens.size || tokens[pos[0]] != ")") {
  163:                     throw IllegalArgumentException("Missing closing parenthesis")
  164:                 }
  165:                 pos[0]++
  166:                 applyPercentIfNeeded(tokens, pos, value)
  167:             }
  168:             token.startsWith("$") -> {
  169:                 val varName = token.drop(1)
  170:                 val value = variables[varName]
  171:                     ?: throw IllegalArgumentException("Variable $token is not set")
  172:                 applyPercentIfNeeded(tokens, pos, value)
  173:             }
  174:             else -> {
  175:                 val value = token.toDouble()
  176:                 applyPercentIfNeeded(tokens, pos, value)
  177:             }
  178:         }
  179:     }
  180: 
  181:     private fun applyPercentIfNeeded(tokens: List<String>, pos: IntArray, value: Double): Double {
  182:         var result = value
  183:         while (pos[0] < tokens.size && tokens[pos[0]] == "%") {
  184:             pos[0]++
  185:             result /= 100.0
  186:         }
  187:         return result
  188:     }
  189: 
  190:     private fun String.startsImplicitMultiplication(): Boolean =
  191:         this == "(" || this == "√" || firstOrNull()?.isDigit() == true || this == "." || startsWith("$")
  192: }
